+fn run_command_async() -> Result<(), ProcessError> {
+    futures_lite::future::block_on(async {
+        let mut child = Command::new("echo").arg("hello").spawn()?;
+        let _status = child.wait_async().await?;
+        Ok::<(), ProcessError>(())
+    })?;
+    Ok(())
+}
